SELECT COUNT(DISTINCT user_id) AS unique_users_played
FROM (
    SELECT user_id FROM quiz_play_history
    UNION
    SELECT user_id FROM game_play_history
);

SELECT title, rating, category_id
FROM quizzes
WHERE featured = 1;

SELECT u.username
FROM users u
WHERE u.user_id IN (
    SELECT qph.user_id
    FROM quiz_play_history qph
)
AND u.user_id NOT IN (
    SELECT gph.user_id
    FROM game_play_history gph
);

SELECT quizzes.title, categories.category_name 
FROM quizzes 
JOIN categories ON quizzes.category_id = categories.category_id;

SELECT title 
FROM quizzes
WHERE plays > 1000;

SELECT quiz_id, title, SQRT(plays) AS plays_square_root
FROM quizzes
ORDER BY rating DESC;

SELECT users.username, quiz_creators.quiz_id
FROM users
JOIN quiz_creators ON users.user_id = quiz_creators.user_id;

SELECT COUNT(rating_id) AS five_star_ratings
FROM game_ratings
WHERE rating = 5;

SELECT quiz_id, COUNT(rating_id) AS total_ratings
FROM quiz_ratings
GROUP BY quiz_id;

SELECT COUNT(DISTINCT quiz_id)
FROM quiz_creators
WHERE user_id IN (SELECT DISTINCT user_id FROM quiz_ratings);

SELECT quiz_id, title, rating 
FROM quizzes
WHERE rating = (
    SELECT MAX(rating) 
    FROM quizzes
);

SELECT AVG(score) AS average_score
FROM quiz_play_history
WHERE play_date BETWEEN 'start_date' AND 'end_date';

SELECT
    (SELECT title FROM games ORDER BY rating DESC LIMIT 1) AS HighestRatedGame,
    (SELECT title FROM quizzes ORDER BY rating DESC LIMIT 1) AS HighestRatedQuiz;
